settings.custom_liquid:
{%- liquid
  assign w = product.metafields.postcard.world.value | default: product.metafields.custom.world.value
-%}
{%- if w -%}
  <div class="pc-pdp-chip-line">
    <span class="pc-pdp-chip" style="background: {{ w.accent_color.value | default: '#E8C36A' }};"></span>
    <span class="pc-pdp-chip-name">{{ w.name.value | upcase }}{% if product.type != blank %} &middot; {{ product.type | upcase }}{% endif %}</span>
  </div>
{%- endif -%}

{%- assign ing = product.metafields.custom.ingredients -%}
{%- if ing != blank -%}
<details class="pc-pdp-collapse">
  <summary class="pc-pdp-collapse__summary">Ingredients</summary>
  <div class="pc-pdp-collapse__body rte">{{ ing | metafield_tag }}</div>
</details>
{%- endif -%}

{%- assign ben = product.metafields.custom.benefits -%}
{%- if ben != blank -%}
<details class="pc-pdp-collapse">
  <summary class="pc-pdp-collapse__summary">Benefits</summary>
  <div class="pc-pdp-collapse__body rte">{{ ben | metafield_tag }}</div>
</details>
{%- endif -%}
